import time
import sys
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

class MyHandler(FileSystemEventHandler):
    def on_created(self, event):
        print(f"Oluşturuldu: {event.src_path}")

    def on_deleted(self, event):
        print(f"Silindi: {event.src_path}")

    def on_modified(self, event):
        print(f"Değiştirildi: {event.src_path}")

    def on_moved(self, event):
        print(f"Taşındı/Yeniden Adlandırıldı: {event.src_path} -> {event.dest_path}")

if __name__ == "__main__":
    # İzlenecek dizin. Komut satırı argümanı olarak verilmezse mevcut dizini kullanır.
    path = sys.argv[1] if len(sys.argv) > 1 else '.'

    event_handler = MyHandler()
    observer = Observer()
    # Dizin ve alt dizinlerdeki değişiklikleri izle
    observer.schedule(event_handler, path, recursive=True)
    observer.start()
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        observer.stop()
    observer.join()
